// ─── LEARNING PLAN ────────────────────────────────────────────────────────────
function buildLearningPlan(domainStates, enrolledGrade) {
  const enrolledNum = gradeToNum(enrolledGrade);
  const items = [];
  const domainOrder = ["OA","NBT","MD","G"];
  for (const domain of domainOrder) {
    const ds = domainStates[domain];
    if (!ds?.resultData) continue;
    const resultNum = ds.resultData.numeric ?? 6;
    const startNum = Math.max(6, Math.floor(resultNum) - (resultNum < 6.5 ? 0 : 1));
    for (let gn = startNum; gn <= enrolledNum; gn++) {
      const grade = numToGrade(gn);
      const standards = CC_STANDARDS_68[grade]?.[domain] || [];
      for (const std of standards) {
        items.push({
          grade, gradeNum:gn, domain,
          code: std.code, desc: std.desc,
          status: gn < Math.floor(resultNum) ? "needs_work" : gn === Math.floor(resultNum) ? "in_progress" : "approaching",
        });
      }
    }
  }
  items.sort((a,b) => {
    if (a.domain !== b.domain) return DOMAIN_WEIGHT[a.domain] - DOMAIN_WEIGHT[b.domain];
    return a.gradeNum - b.gradeNum;
  });
  return items;
}

